// test/vectors/slhdsa_sigver.ts
//
// NIST ACVP SLH-DSA-sigVer test vectors (FIPS 205).
//
// Source:
//   ACVP-Server/gen-val/json-files/SLH-DSA-sigVer-FIPS205/internalProjection.json
//   @see https://github.com/usnistgov/ACVP-Server/tree/master/gen-val/json-files/SLH-DSA-sigVer-FIPS205
//   pin: 15c0f3deeefbfa8cb6cd32a99e1ca3b738c66bf0 (v1.1.0.42, 2026-04-16)
//   vsId=53, algorithm=SLH-DSA, mode=sigVer, revision=FIPS205, isSample=true
//
// Curated SHAKE-fast subset.
// Each test carries `testPassed: bool` (whether the signature should
// verify) and `reason: string` (failure cause for negative tests).
// HashSLH-DSA preHash cases are merged via the same `preHash` group
// discriminator that sigGen uses.
//
// Per parameter set: 2 pure-pass + 3 pure-fail + 2 preHash-pass +
// 2 preHash-fail = 9. Total: 27 across 128f/192f/256f.

export type ParameterSet = 'SLH-DSA-SHAKE-128f' | 'SLH-DSA-SHAKE-192f' | 'SLH-DSA-SHAKE-256f';
export type SignatureInterface = 'external';
export type PreHash = 'pure' | 'preHash';

export interface SigVerVector {
	tcId:               number;
	tgId:               number;
	testPassed:         boolean;
	parameterSet:       ParameterSet;
	signatureInterface: SignatureInterface;
	preHash:            PreHash;
	hashAlg:            string;
	reason:             string;
	pk:                 string;
	signature:          string;
	message:            string;
	context:            string;
}

